import type { RenderSlide, RenderConfig, RenderTaskPayload } from '@/lib/queue/types';

// ─── Factories ───────────────────────────────────────────

export function createMockSlide(overrides: Partial<RenderSlide> = {}): RenderSlide {
  return {
    id: `slide-${Math.random().toString(36).slice(2, 8)}`,
    orderIndex: 0,
    title: 'Test Slide',
    content: '<p>Test content</p>',
    duration: 5,
    transition: 'fade',
    transitionDuration: 0.5,
    ...overrides,
  };
}

export function createMockRenderConfig(overrides: Partial<RenderConfig> = {}): RenderConfig {
  return {
    resolution: '1920x1080',
    fps: 30,
    quality: 'high',
    format: 'mp4',
    codec: 'h264',
    bitrate: '5000k',
    audioCodec: 'aac',
    audioBitrate: '128k',
    test: true,
    includeAudio: false,
    includeSubtitles: false,
    ...overrides,
  };
}

export function createMockRenderPayload(overrides: Partial<RenderTaskPayload> = {}): RenderTaskPayload {
  return {
    jobId: `job-${Math.random().toString(36).slice(2, 8)}`,
    projectId: `proj-${Math.random().toString(36).slice(2, 8)}`,
    userId: `user-${Math.random().toString(36).slice(2, 8)}`,
    type: 'render',
    slides: [createMockSlide()],
    config: createMockRenderConfig(),
    ...overrides,
  };
}

// ─── Request/Response Helpers ────────────────────────────

export function createMockRequest(options: {
  method?: string;
  url?: string;
  body?: Record<string, unknown>;
  headers?: Record<string, string>;
} = {}): Request {
  const { method = 'GET', url = 'http://localhost:3000', body, headers = {} } = options;

  return new Request(url, {
    method,
    headers: {
      'Content-Type': 'application/json',
      ...headers,
    },
    ...(body ? { body: JSON.stringify(body) } : {}),
  });
}

// ─── Timer Utilities ─────────────────────────────────────

export function advanceTimers(ms: number): void {
  jest.advanceTimersByTime(ms);
}

export function waitFor(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

// ─── Assertion Helpers ───────────────────────────────────

export function expectJsonResponse(response: Response, status: number): void {
  expect(response.status).toBe(status);
  expect(response.headers.get('content-type')).toContain('application/json');
}
